            "tag": "@example",
            "content": [
              {
                "kind": "code",
                "text": "```js\nconst swiper = new Swiper('.swiper', {\n  effect: 'creative',\n  creativeEffect: {\n    prev: {\n      // will set `translateZ(-400px)` on previous slides\n      translate: [0, 0, -400],\n    },\n    next: {\n      // will set `translateX(100%)` on next slides\n      translate: ['100%', 0, 0],\n    },\n  },\n});\n```"
              }
            ]
